import{_ as t,a as r}from"./retained-interval-demo.322569c3.js";import{_ as i,r as s,o as d,c as n,a as e,d as a,b as c,w as h,e as p}from"./app.50ad9e00.js";const m={},l=e("h1",{id:"问答集合",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#问答集合","aria-hidden":"true"},"#"),a(" 问答集合")],-1),_=e("h2",{id:"听说可以连续复制-一次性添加-但是没有效果-应该怎么办",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#听说可以连续复制-一次性添加-但是没有效果-应该怎么办","aria-hidden":"true"},"#"),a(" 听说可以连续复制，一次性添加，但是没有效果，应该怎么办？")],-1),u=e("p",null,"连续复制的功能是结合快捷指令使用的，快捷指令是苹果自己的一个应用，如果已经删除了，可以先去App Store下载一下。",-1),f=p('<h2 id="我现在快捷键盘只想进去就打开剪切板历史-可以吗" tabindex="-1"><a class="header-anchor" href="#我现在快捷键盘只想进去就打开剪切板历史-可以吗" aria-hidden="true">#</a> 我现在快捷键盘只想进去就打开剪切板历史，可以吗？</h2><p>可以的，需要在设置中，找到「键盘」部分，然后找到「短时记忆面板留存时长」，选择「一直」就可以了。</p><p>这样每次打开键盘会自动进入「短时记忆」，进行快捷粘贴了。</p><h2 id="在ios16中经常跳出允许粘贴的提示-非常影响体验" tabindex="-1"><a class="header-anchor" href="#在ios16中经常跳出允许粘贴的提示-非常影响体验" aria-hidden="true">#</a> 在iOS16中经常跳出允许粘贴的提示，非常影响体验</h2><p>需要前往系统「设置」，找到「ToMemo」。进入设置后，将「从其他App粘贴」功能设置为「允许」</p><details class="custom-container details"><summary>设置结果如图</summary><p><img src="'+t+'" alt="ios16-paste-warning.jpg"></p></details><h2 id="键盘添加后-在切换键盘中找不到tomemo-怎么办" tabindex="-1"><a class="header-anchor" href="#键盘添加后-在切换键盘中找不到tomemo-怎么办" aria-hidden="true">#</a> 键盘添加后，在切换键盘中找不到ToMemo，怎么办？</h2><p>这个是因为系统有一些缓存，只要强制关闭当前软件，重新打开，就可以看到了。</p><p>如果还是不行，尝试重新添加ToMemo键盘。</p><h2 id="设置中的留存时长是什么意思" tabindex="-1"><a class="header-anchor" href="#设置中的留存时长是什么意思" aria-hidden="true">#</a> 设置中的留存时长是什么意思？</h2><p>现在设置中有两个留存时长，操作原理是一样的。</p><p><strong>它是「使用后面板留存时长」的简写。</strong></p><p>「短时记忆面板留存时长」</p><ul><li>如果设置了<code>1分钟</code>，在进入ToMemo键盘后，点击闪电进入「短时记忆」，并点击输入的内容A。只要在<code>1分钟内</code>，再次唤出ToMemo键盘，会自动进入「短时记忆」，方便快速添加里面的其他内容</li><li>如果设置成了<code>一直</code>，意味着每次唤出键盘，首先进入「短时记忆」，方便直接粘贴剪切板历史内容。</li></ul><p>「列表留存时长」</p><ul><li>只能在键盘首屏为列表时使用</li><li>只要设置的时长大于0，只要在使用ToMemo键盘时，进入列表，点击Memo输入后，会在设置的X分钟内，凡是再次唤出ToMemo键盘，会自动进入上面选择的列表。</li></ul><p>留存时长会相互覆盖的。比如在短时记忆中点击输入后，下一次在列表中选择了一条Memo输入，那么下次进来就根据是否满足列表留存的条件进行判断展示了。</p><details class="custom-container details"><summary>留存时长演示视频</summary><p><img src="'+r+'" alt="retained-interval-demo.gif"></p></details><h2 id="我需要创建大量的memo-怎么办" tabindex="-1"><a class="header-anchor" href="#我需要创建大量的memo-怎么办" aria-hidden="true">#</a> 我需要创建大量的Memo，怎么办？</h2><p>ToMemo拥有<strong>批量导入</strong>的功能。</p><p>首选需要一个列表，进入列表详情页，右下角有批量添加的按钮。</p><p>点击进入后，按照导入界面中的模板样例整理内容，然后直接粘贴进来。当然也可以在输入框中编辑，右下角有分割线快捷输入按钮。</p><p>通过预览按钮看一下是否符合预期，然后就可以保存导入了。</p>',23);function x(M,g){const o=s("RouterLink");return d(),n("div",null,[l,_,u,e("p",null,[a("然后参考"),c(o,{to:"/short-term-memory-advance/"},{default:h(()=>[a("「短时记忆+快捷键/使用快捷指令添加短时记忆」")]),_:1}),a("中的详细教程，包含了快捷指令的下载地址，以及辅助触控的结合方式，可以按照演示视频一步步添加。")]),f])}const v=i(m,[["render",x],["__file","index.html.vue"]]);export{v as default};
